// lib/db.js
import { unstable_cache } from "next/cache";

// ---------------------------------------------------------------------------
// Simulated product database — in production this would be PostgreSQL, a PIM
// API, or another backing store.  Module-level state means it resets on every
// dev server restart; a real DB would persist naturally.
// ---------------------------------------------------------------------------

let products = [
  { id: 1, name: "Laptop Pro 15″", sku: "LAP-001", price: 1299.99, stock: 42, status: "active" },
  { id: 2, name: "Wireless Phone", sku: "PHN-002", price: 799.99, stock: 128, status: "active" },
  { id: 3, name: "10″ Tablet", sku: "TAB-003", price: 499.99, stock: 87, status: "active" },
  { id: 4, name: "Noise-Cancelling Headphones", sku: "HPH-004", price: 249.99, stock: 0, status: "inactive" },
  { id: 5, name: "Smart Watch", sku: "WCH-005", price: 349.99, stock: 65, status: "active" },
];

let lastSync = new Date("2026-07-14T12:00:00Z");

// ---------------------------------------------------------------------------
// Cached catalog reader  (used by the admin page for day-to-day browsing)
//
// Wrapped with unstable_cache so repeated requests served from the same
// render cycle (or within the cache lifetime) skip the simulated DB delay.
// The "products" tag lets us bulk-invalidate from the sync action.
// ---------------------------------------------------------------------------

export const getCachedProducts = unstable_cache(
  async () => {
    // Simulate a database round-trip.
    await new Promise((resolve) => setTimeout(resolve, 100));

    return {
      items: products.map((p) => ({ ...p })),
      lastSync: lastSync.toISOString(),
      total: products.length,
    };
  },
  ["admin-products-all"],
  { tags: ["products"] },
);

// ---------------------------------------------------------------------------
// Direct (non-cached) reader — useful after a sync when we want to bypass the
// stale cache entry and confirm the new data is visible.
// ---------------------------------------------------------------------------

export async function getAllProducts() {
  await new Promise((resolve) => setTimeout(resolve, 100));
  return {
    items: products.map((p) => ({ ...p })),
    lastSync: lastSync.toISOString(),
    total: products.length,
  };
}

// ---------------------------------------------------------------------------
// Background sync  — simulates pulling updated pricing / inventory from an
// upstream ERP or PIM system and writing it into the local database.
//
// In production this would call an external API, transform the response, and
// upsert rows.  The key property for the admin experience is that it runs
// *after* the server action returns so the operator isn't blocked.
// ---------------------------------------------------------------------------

export async function syncFromERP() {
  // Simulate the latency of a real ERP round-trip (network + processing).
  await new Promise((resolve) => setTimeout(resolve, 4_000));

  // "New data from the upstream" — prices updated, stock adjusted, a new SKU
  // added, one delisted.
  products = [
    { id: 1, name: "Laptop Pro 15″ 2026 Edition", sku: "LAP-001", price: 1199.99, stock: 55, status: "active" },
    { id: 2, name: "Wireless Phone", sku: "PHN-002", price: 749.99, stock: 200, status: "active" },
    { id: 3, name: "10″ Tablet", sku: "TAB-003", price: 499.99, stock: 87, status: "active" },
    { id: 4, name: "Noise-Cancelling Headphones", sku: "HPH-004", price: 199.99, stock: 30, status: "active" },
    { id: 5, name: "Smart Watch Series 2", sku: "WCH-005", price: 379.99, stock: 42, status: "active" },
    { id: 6, name: "Bluetooth Speaker", sku: "SPK-006", price: 89.99, stock: 150, status: "active" },
  ];

  lastSync = new Date();
}


